changeSet.sql:
CREATE TABLE class_saving_throw (
    class_id uuid NOT NULL REFERENCES character_class(class_id) ON DELETE CASCADE,
    ability_score_id uuid NOT NULL REFERENCES ability_score(ability_score_id),
    PRIMARY KEY (class_id, ability_score_id)
);

CREATE TABLE class_primary_ability (
    class_id uuid NOT NULL REFERENCES character_class(class_id) ON DELETE CASCADE,
    ability_score_id uuid NOT NULL REFERENCES ability_score(ability_score_id),
    PRIMARY KEY (class_id, ability_score_id)
);

CREATE TABLE class_skill_option (
    class_id uuid NOT NULL REFERENCES character_class(class_id) ON DELETE CASCADE,
    skill_id uuid NOT NULL REFERENCES skill(skill_id),
    PRIMARY KEY (class_id, skill_id)
);

rollback.sql:
DROP TABLE class_skill_option;
DROP TABLE class_primary_ability;
DROP TABLE class_saving_throw;
